INSERT INTO desa (id, nama_desa, kecamatan, kabupaten, latitude, longitude, deskripsi) OVERRIDING SYSTEM VALUE VALUES (1, 'Desa Sukajaya', 'Sukajaya', 'Kabupaten Bogor', -6.6189, 106.5123, 'Desa Sukajaya terletak di kawasan perbukitan Kecamatan Sukajaya, Kabupaten Bogor, Jawa Barat, pada ketinggian 700-1.100 mdpl dengan tanah vulkanik subur. Terkenal dengan kopi robusta, madu hutan, dan anyaman bambu.');
