INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (1, 'Madu Hutan Sukajaya', 68000, 68, '/images/produk/madu_hutan_sukajaya.jpg', 'Madu murni hasil lebah liar dari kawasan hutan Sukajaya.', '250 ml', '100% alami, kaya antioksidan.', 'Lebah mencari nektar dari bunga kaliandra, kopi, dan berbagai tanaman hutan yang tumbuh alami di perbukitan Sukajaya. Proses panen dilakukan secara hati-hati agar koloni lebah tetap lestari. Setiap tetes madu membawa cita rasa khas hutan pegunungan Bogor yang masih terjaga keasriannya.', 3, 1, NOW());
