INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (2, 'Madu Kaliandra Premium', 125000, 107, '/images/produk/madu_kaliandra_premium.jpg', 'Madu premium dari bunga kaliandra.', '500 ml', 'Aroma floral, kadar air rendah.', 'Saat musim bunga kaliandra mekar, lebah menghasilkan madu dengan aroma bunga yang khas dan rasa manis yang lembut. Varian ini hanya tersedia pada musim tertentu sehingga menjadi produk premium desa.', 3, 2, NOW());
