INSERT INTO desa (id, nama_desa, kecamatan, kabupaten, latitude, longitude, deskripsi) OVERRIDING SYSTEM VALUE VALUES (3, 'Desa Penglipuran', 'Bangli', 'Kabupaten Bangli', -8.4522, 115.3524, 'Desa adat Penglipuran di Bangli, Bali, terkenal dengan kelestarian budaya dan arsitektur tradisional. Dikelilingi hutan bambu, mendukung budidaya jeruk kintamani, kakao, kopi, dan lebah madu trigona.');
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (28, 'Kelompok Tani Madu Penglipuran (Pak I Wayan Sudarma)', 'Kelompok Tani Madu Penglipuran (Pak I Wayan Sudarma)', 'Banjar Penglipuran, Desa Penglipuran, Kec. Bangli, Kab. Bangli, Bali 80619', '6281234561301', '2012', '/images/petani/lakiiii.jpeg', 3);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (49, 'Madu Trigona Penglipuran', 75000, 50, '/images/produk/madu_trigona_penglipuran.jpg', 'Madu murni dari lebah Trigona tanpa sengat dengan cita rasa manis sedikit asam.', '250 ml', 'Kaya propolis alami, antioksidan tinggi, dipanen tanpa merusak koloni lebah.', 'Di balik hutan bambu yang rindang, masyarakat Desa Penglipuran membudidayakan lebah Trigona secara alami. Lebah ini mengumpulkan nektar dari berbagai bunga liar, tanaman kopi, dan rempah yang tumbuh di lingkungan desa. Berkat udara yang sejuk dan ekosistem yang masih terjaga, madu yang dihasilkan memiliki aroma khas, rasa unik, dan kandungan propolis yang lebih tinggi dibanding madu biasa.', 3, 28, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (29, 'Pak I Wayan Sudarma', 'Pak I Wayan Sudarma', 'Banjar Penglipuran, Desa Penglipuran, Kec. Bangli, Kab. Bangli, Bali 80619', '6281234561301', '2012', '/images/petani/laki-laki.jpeg', 3);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (50, 'Madu Trigona Premium', 135000, 60, '/images/produk/cookies_madu.jpg', 'Madu premium hasil panen terbatas.', '500 ml', 'Kadar air rendah, kualitas premium.', 'Setiap musim panen hanya sebagian kecil madu terbaik yang dipilih menjadi varian Premium. Madu dipanen secara manual tanpa merusak sarang sehingga kelestarian lebah tetap terjaga untuk generasi berikutnya.', 3, 29, NOW());
