INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (51, 'Honey Lemon Bali', 45000, 95, '/images/produk/honey_lemon.jpg', 'Minuman madu dengan lemon segar Bali.', '300 ml', 'Menyegarkan dan meningkatkan daya tahan tubuh.', 'Perpaduan madu Trigona dengan lemon lokal Bali menghasilkan minuman herbal yang banyak dinikmati wisatawan setelah berkeliling Desa Penglipuran.', 3, 30, NOW());
