INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (65, 'Keranjang Anyaman Bambu', 75000, 35, '/images/produk/keranjang_anyaman_bambu.jpg', 'Keranjang handmade dari bambu lokal.', '', 'Ramah lingkungan.', 'Hutan bambu yang mengelilingi Desa Penglipuran menjadi sumber bahan baku utama. Setiap keranjang dianyam secara manual menggunakan teknik tradisional yang diwariskan dari generasi ke generasi.', 4, 37, NOW());
