INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (66, 'Lampu Hias Bambu', 120000, 70, '/images/produk/lampu_hias_bambu.jpg', 'Lampu dekoratif.', '', 'Motif ukiran Bali.', 'Motif ukiran pada lampu terinspirasi dari ornamen rumah adat Bali yang menjadi identitas Desa Penglipuran.', 4, 38, NOW());
