INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (67, 'Tempat Tisu Bambu', 55000, 59, '/images/produk/tempat_tisu_bambu.jpg', 'Tempat tisu handmade.', '', 'Finishing premium.', 'Produk dibuat dari bambu pilihan yang telah dikeringkan secara alami agar lebih kuat dan tahan lama.', 4, 39, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (68, 'Vas Bunga Bambu', 85000, 41, '/images/produk/vas_bunga_bambu.jpg', 'Vas dekoratif.', '', 'Handmade.', 'Setiap vas memiliki pola serat bambu yang berbeda sehingga tidak ada dua produk yang benar-benar sama.', 4, 39, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (40, 'UMKM Rasa Penglipuran', 'UMKM Rasa Penglipuran', 'Banjar Kaja, Desa Penglipuran', '6281234561311', '2013', '/images/petani/laki-laki.jpeg', 3);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (69, 'Pie Susu Bali', 35000, 117, '/images/produk/pie_susu_bali.jpg', 'Pie susu khas Bali.', '200 gr', 'Resep tradisional.', 'Pie susu menjadi salah satu oleh-oleh favorit wisatawan yang berkunjung ke Bali. Produk ini dibuat menggunakan resep keluarga yang telah diwariskan selama puluhan tahun.', 6, 40, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (70, 'Keripik Pisang', 22000, 28, '/images/produk/keripik_pisang.jpg', 'Keripik pisang renyah.', '200 gr', 'Tanpa pengawet.', 'Pisang lokal yang melimpah diolah menjadi keripik agar memiliki umur simpan lebih panjang sekaligus meningkatkan nilai jual hasil panen masyarakat.', 6, 40, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (41, 'UMKM Cokelat Bali Asri', 'UMKM Cokelat Bali Asri', 'Banjar Kelod, Desa Penglipuran', '6281234561312', '2018', '/images/petani/lelaki.jpeg', 3);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (71, 'Dodol Kakao', 38000, 58, '/images/produk/dodol_kakao.jpg', 'Dodol berbahan kakao lokal.', '250 gr', 'Mengandung kakao asli.', 'Dodol ini menggabungkan resep tradisional Bali dengan kakao fermentasi lokal sehingga menghasilkan rasa manis berpadu aroma cokelat yang khas.', 6, 41, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (72, 'Cookies Kopi Bali', 32000, 106, '/images/produk/cookies_kopi_bali.jpg', 'Cookies dengan bubuk kopi Arabika Bali.', '180 gr', 'Aroma kopi kuat.', 'Biji kopi Arabika Penglipuran dipanggang terlebih dahulu sebelum diolah menjadi cookies yang menjadi favorit wisatawan sebagai buah tangan khas Bali.', 2, 41, NOW());
INSERT INTO desa (id, nama_desa, kecamatan, kabupaten, latitude, longitude, deskripsi) OVERRIDING SYSTEM VALUE VALUES (4, 'Desa Cibodas', 'Lembang', 'Kabupaten Bandung Barat', -6.8123, 107.6512, 'Desa Cibodas di Lembang, Bandung Barat, pada ketinggian 1.250-1.500 mdpl. Tanah vulkanik subur ideal untuk sayuran organik seperti brokoli dan stroberi, serta kopi arabika dan lebah madu kaliandra.');
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (42, 'Pak Dedi Suhendar', 'Pak Dedi Suhendar', 'Jl. Maribaya RT 02/RW 03, Desa Cibodas, Kec. Lembang, Kab. Bandung Barat', '6281234561401', '2010', '/images/petani/lelakii.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (73, 'Brokoli Segar Grade A', 18000, 108, '/images/produk/brokoli_segar.jpg', 'Brokoli segar hasil panen harian dengan warna hijau cerah dan tekstur padat.', '500 gr', 'Dipanen setiap pagi, bebas pengawet, kaya vitamin C dan serat.', 'Di lereng pegunungan Desa Cibodas pada ketinggian sekitar 1.350 mdpl, brokoli ini tumbuh di tanah vulkanik yang subur dengan suhu sejuk 16–23°C. Kabut pagi menjaga kelembapan tanaman sehingga menghasilkan kuntum yang padat, renyah, dan berwarna hijau pekat. Pak Dedi telah merawat lahan ini selama lebih dari 15 tahun dengan sistem panen harian agar setiap brokoli sampai ke tangan pembeli dalam kondisi paling segar.', 5, 42, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (43, 'Pak Asep Mulyana', 'Pak Asep Mulyana', 'Jl. Cibodas RT 01/RW 05, Desa Cibodas', '6281234561402', '2008', '/images/petani/laki.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (74, 'Brokoli Segar Grade Premium', 25000, 112, '/images/produk/brokoli_segar.jpg', 'Brokoli pilihan dengan ukuran seragam dan kualitas premium.', '500 gr', 'Grade restoran dan hotel, ukuran besar, warna hijau pekat.', 'Tidak semua brokoli berhasil menjadi Grade Premium. Setelah dipanen, hanya sekitar 30% hasil panen terbaik yang lolos proses seleksi berdasarkan ukuran, warna, dan kepadatan bunga. Brokoli pilihan inilah yang menjadi favorit restoran di kawasan Bandung dan Lembang.', 5, 43, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (44, 'Cibodas Fresh Farm', 'Cibodas Fresh Farm', 'Jl. Maribaya RT 04/RW 02, Desa Cibodas', '6281234561403', '2018', '/images/petani/laki2.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (75, 'Frozen Broccoli', 28000, 47, '/images/produk/frozen_broccoli.jpg', 'Brokoli segar yang dibekukan dengan teknologi quick freezing.', '500 gr', 'Nutrisi tetap terjaga, praktis dimasak.', 'Sesaat setelah dipanen, brokoli langsung dibersihkan dan dibekukan menggunakan metode quick freezing. Proses ini menjaga warna hijau alami, tekstur, dan kandungan gizinya sehingga pembeli tetap merasakan kesegaran layaknya baru dipanen dari kebun.', 5, 44, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (45, 'Ibu Rina Handayani', 'Ibu Rina Handayani', 'Jl. Maribaya RT 03/RW 01, Desa Cibodas', '6281234561404', '2019', '/images/petani/pr.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (76, 'Keripik Brokoli Original', 22000, 81, '/images/produk/keripik_brokoli.jpg', 'Keripik sehat berbahan brokoli segar.', '150 gr', 'Tanpa pengawet, rendah minyak.', 'Berawal dari banyaknya brokoli yang tidak lolos sortir karena ukuran kurang sempurna, ibu-ibu UMKM Desa Cibodas mengolahnya menjadi keripik sehat yang kini menjadi oleh-oleh khas daerah. Produk ini membantu mengurangi limbah hasil panen sekaligus meningkatkan pendapatan petani.', 5, 45, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (77, 'Keripik Brokoli Balado', 24000, 71, '/images/produk/keripik_brokoli.jpg', 'Keripik brokoli dengan bumbu balado khas Nusantara.', '150 gr', 'Pedas gurih, tanpa MSG berlebih.', 'Perpaduan brokoli segar dataran tinggi dengan racikan bumbu balado menghasilkan camilan unik yang tetap mempertahankan rasa alami brokoli namun dengan sensasi pedas yang menggugah selera.', 5, 45, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (46, 'Pak Agus Setiawan', 'Pak Agus Setiawan', 'Jl. Cibodas RT 02/RW 06, Desa Cibodas', '6281234561405', '2006', '/images/petani/lakik.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (78, 'Kentang Segar', 22000, 102, '/images/produk/kentang_segar.jpg', 'Kentang dataran tinggi dengan tekstur padat.', '1 kg', 'Cocok digoreng maupun direbus.', 'Kentang ini tumbuh di lahan vulkanik Desa Cibodas yang memiliki suhu rendah sehingga proses pembentukan umbi berlangsung lebih lambat. Hasilnya adalah kentang dengan tekstur lebih padat, rasa lebih manis alami, dan tidak mudah hancur saat dimasak.', 1, 46, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (79, 'Kentang Segar Premium', 28000, 68, '/images/produk/kentang_segar.jpg', 'Kentang pilihan berukuran besar dan seragam.', '1 kg', 'Grade premium, cocok untuk restoran.', 'Hanya kentang dengan ukuran terbaik yang dipilih menjadi Grade Premium. Setiap umbi disortir secara manual untuk memastikan kualitas terbaik sampai ke konsumen.', 1, 46, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (47, 'Cibodas Frozen Food', 'Cibodas Frozen Food', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459001', '2020', '/images/petani/lakikk.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (80, 'Frozen French Fries', 32000, 30, '/images/produk/frozen_broccoli.jpg', 'Kentang premium siap goreng.', '500 gr', 'Praktis, renyah, tanpa pengawet.', 'Kentang dipotong dan dibekukan tidak lama setelah panen sehingga rasa alami dan teksturnya tetap terjaga. Produk ini menjadi solusi praktis tanpa mengurangi kualitas hasil panen lokal.', 6, 47, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (48, 'Pak Irfan Hidayat', 'Pak Irfan Hidayat', 'Jl. Maribaya RT 01/RW 04, Desa Cibodas', '6281234561406', '2017', '/images/petani/lakilaki.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (81, 'Keripik Kentang Original', 20000, 98, '/images/produk/keripik_kentang.jpg', 'Keripik kentang tipis dan renyah.', '180 gr', 'Kentang lokal pilihan.', 'Keripik ini dibuat dari kentang pilihan yang dipanen langsung dari petani Desa Cibodas. Setiap irisan digoreng perlahan agar menghasilkan kerenyahan alami tanpa menghilangkan cita rasa khas kentang pegunungan.', 6, 48, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (82, 'Keripik Kentang BBQ', 22000, 100, '/images/produk/keripik_kentang.jpg', 'Keripik kentang rasa BBQ.', '180 gr', 'Bumbu rempah premium.', 'Varian BBQ menjadi favorit wisatawan yang berkunjung ke Lembang. Perpaduan kentang dataran tinggi dengan bumbu rempah menghasilkan rasa gurih dan aroma yang khas.', 6, 48, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (49, 'Pak Wawan Gunawan', 'Pak Wawan Gunawan', 'Jl. Cibodas RT 05/RW 02, Desa Cibodas', '6281234561407', '2011', '/images/petani/lakiiii.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (83, 'Wortel Segar', 12000, 63, '/images/produk/wortel_segar.jpg', 'Wortel segar kaya beta-karoten.', '500 gr', 'Dipanen harian, warna cerah.', 'Udara sejuk Desa Cibodas membuat wortel tumbuh lebih perlahan sehingga rasa manis alaminya berkembang dengan sempurna. Tanah vulkanik yang kaya mineral juga menghasilkan warna oranye yang lebih cerah.', 5, 49, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (84, 'Wortel Segar Premium', 16000, 41, '/images/produk/wortel_segar.jpg', 'Wortel pilihan ukuran seragam.', '500 gr', 'Grade premium.', 'Setiap wortel dipilih berdasarkan ukuran, bentuk, dan warna terbaik sehingga cocok untuk kebutuhan hotel maupun restoran.', 5, 49, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (50, 'Fresh Cibodas Juice', 'Fresh Cibodas Juice', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459002', '2021', '/images/petani/laki-laki.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (85, 'Jus Wortel Murni', 18000, 39, '/images/produk/jus_wortel.jpg', 'Jus wortel tanpa tambahan pewarna.', '250 ml', '100% wortel segar.', 'Jus ini dibuat dari wortel yang baru dipanen pada pagi hari. Tanpa tambahan pewarna maupun pengawet, rasa manis alami berasal langsung dari hasil bumi Desa Cibodas.', 5, 50, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (86, 'Jus Wortel Premium', 22000, 73, '/images/produk/jus_wortel.jpg', 'Jus wortel premium.', '300 ml', 'Menggunakan wortel pilihan.', 'Menggunakan wortel Grade Premium yang memiliki kandungan air lebih tinggi sehingga menghasilkan jus dengan rasa lebih segar dan tekstur lebih lembut.', 5, 50, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (51, 'Green Valley Farm', 'Green Valley Farm', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459003', '2019', '/images/petani/lelaki.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (87, 'Salad Pack Ready to Eat', 25000, 89, '/images/produk/salad_pack.jpg', 'Salad siap santap.', '300 gr', 'Sayuran segar dipanen harian.', 'Setiap pagi sebelum matahari tinggi, sayuran dipanen lalu dicuci menggunakan air pegunungan yang jernih. Setelah melalui proses sortir, sayuran langsung dikemas agar kesegarannya tetap terjaga.', 5, 51, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (88, 'Caesar Salad Pack', 32000, 53, '/images/produk/salad_pack.jpg', 'Salad dengan saus Caesar premium.', '350 gr', 'Sayuran premium.', 'Menggunakan selada romaine pilihan yang tumbuh di udara sejuk Lembang sehingga menghasilkan tekstur lebih renyah dan rasa yang lebih segar dibandingkan sayuran dataran rendah.', 5, 51, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (89, 'Sayuran Siap Masak (Pakcoy Mix)', 20000, 98, '/images/produk/pakcoy.jpg', 'Paket sayuran siap olah.', '500 gr', 'Praktis, segar.', 'Pakcoy, sawi, dan sayuran lainnya dipanen pada pagi hari lalu langsung dikemas agar pelanggan dapat menikmati kesegaran hasil panen tanpa harus membersihkan atau memilah kembali.', 5, 42, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (52, 'Ibu Siti Nurhayati', 'Ibu Siti Nurhayati', 'Jl. Maribaya RT 04/RW 05, Desa Cibodas', '6281234561408', '2012', '/images/petani/prmpuan.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (90, 'Stroberi Segar', 35000, 107, '/images/produk/stroberi_segar.jpg', 'Stroberi merah segar hasil kebun Lembang.', '500 gr', 'Manis alami, aroma harum.', 'Stroberi tumbuh optimal di dataran tinggi Lembang dengan suhu sejuk dan sinar matahari yang cukup. Buah dipetik satu per satu saat matang sempurna sehingga menghasilkan rasa manis dan aroma yang khas.', 1, 52, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (91, 'Stroberi Segar Premium', 45000, 39, '/images/produk/stroberi_segar.jpg', 'Stroberi ukuran besar pilihan.', '500 gr', 'Grade premium.', 'Hanya buah dengan ukuran besar, warna merah merata, dan tanpa cacat yang dipilih menjadi Grade Premium. Buah ini sering digunakan oleh hotel dan restoran sebagai bahan dessert.', 1, 52, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (53, 'Ibu Lina Marlina', 'Ibu Lina Marlina', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459004', '2016', '/images/petani/perempuan.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (92, 'Selai Stroberi Homemade', 28000, 75, '/images/produk/selai_stroberi.jpg', 'Selai stroberi rumahan.', '250 gr', 'Tanpa pengawet.', 'Resep selai ini diwariskan secara turun-temurun. Stroberi segar dimasak perlahan dalam jumlah kecil sehingga rasa buah tetap mendominasi tanpa tambahan perasa buatan.', 6, 53, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (93, 'Selai Stroberi Premium', 35000, 109, '/images/produk/selai_stroberi.jpg', 'Selai premium dengan kandungan buah tinggi.', '250 gr', 'Mengandung lebih dari 70% buah asli.', 'Menggunakan stroberi Grade Premium yang dipanen dari kebun terbaik Desa Cibodas. Kandungan buah yang tinggi menghasilkan tekstur lebih lembut dan rasa yang lebih autentik.', 6, 53, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (54, 'Berry Valley UMKM', 'Berry Valley UMKM', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459005', '2018', '/images/petani/lelakii.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (94, 'Sirup Stroberi', 30000, 70, '/images/produk/sirup_stroberi.jpg', 'Sirup buah stroberi asli.', '500 ml', 'Tanpa pewarna sintetis.', 'Sirup dibuat dari sari buah stroberi segar yang dipanen pada musim terbaik. Aroma khas pegunungan tetap terasa di setiap tetesnya.', 6, 54, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (95, 'Sirup Stroberi Premium', 38000, 107, '/images/produk/sirup_stroberi.jpg', 'Sirup premium dengan ekstrak buah lebih banyak.', '500 ml', 'Rasa lebih pekat.', 'Menggunakan buah premium dengan kadar gula alami yang tinggi sehingga menghasilkan rasa yang lebih kaya tanpa perlu banyak tambahan pemanis.', 6, 54, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (55, 'Cibodas Berry Farm', 'Cibodas Berry Farm', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459006', '2019', '/images/petani/laki.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (96, 'Stroberi Beku (Frozen)', 40000, 47, '/images/produk/stroberi_beku.jpg', 'Stroberi beku hasil pembekuan cepat.', '500 gr', 'Cocok untuk smoothie dan dessert.', 'Tidak semua stroberi dapat dijual dalam kondisi segar. Untuk mengurangi limbah pangan, buah yang telah dipanen segera dibekukan menggunakan teknologi quick freezing sehingga warna, rasa, dan kandungan gizinya tetap terjaga. Setiap pembelian produk ini juga membantu mengurangi hasil panen yang terbuang dan mendukung keberlanjutan UMKM lokal.', 6, 55, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (56, 'Pak Hendra Kusnadi', 'Pak Hendra Kusnadi', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459007', '2009', '/images/petani/laki2.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (97, 'Kubis Organik', 18000, 58, '/images/produk/kubis.jpg', 'Kubis organik segar dengan daun berlapis rapat, tekstur renyah, dan rasa manis alami. Cocok untuk tumisan, sup, salad, maupun olahan fermentasi.', '1 kg', 'Dibudidayakan tanpa pestisida kimia berlebihan, dipanen setiap pagi, kaya vitamin C dan serat.', 'Kubis organik ini tumbuh di lahan pertanian Desa Cibodas pada ketinggian sekitar 1.400 mdpl. Udara pegunungan yang sejuk, kabut pagi, serta tanah vulkanik yang kaya mineral membuat pertumbuhan kubis berlangsung lebih lambat sehingga menghasilkan daun yang lebih padat, renyah, dan memiliki rasa manis alami. Pak Hendra telah mengelola kebunnya selama lebih dari 16 tahun dengan menerapkan rotasi tanaman dan penggunaan pupuk kompos agar kesuburan tanah tetap terjaga. Setiap pembelian kubis ini turut mendukung pertanian ramah lingkungan di dataran tinggi Lembang.', 5, 56, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (57, 'Ibu Sri Wahyuni', 'Ibu Sri Wahyuni', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459008', '2014', '/images/petani/perempuan (2).jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (98, 'Sawi Hijau', 10000, 64, '/images/produk/sawi_hijau.jpg', 'Sawi hijau segar dengan daun lebar berwarna hijau cerah dan batang yang renyah. Sangat cocok untuk tumisan, mie, bakso, maupun hotpot.', '500 gr', 'Dipanen kurang dari 24 jam sebelum dikirim, kaya vitamin A, C, dan kalsium, bebas pengawet.', 'Sawi hijau ini ditanam di lereng Desa Cibodas yang memiliki suhu rata-rata 18°C. Kondisi udara yang dingin membantu daun tumbuh lebih tebal dan segar. Setiap pagi sebelum matahari terbit, para petani mulai memanen sawi agar kandungan air di dalam daun tetap terjaga. Tradisi panen pagi ini telah dilakukan turun-temurun untuk memastikan konsumen mendapatkan sayuran dengan kualitas terbaik.', 5, 57, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (58, 'Pak Rudi Hartono', 'Pak Rudi Hartono', 'Kp. Citeko RT 01/RW 05, Desa Tugu Utara', '6281234561203', '2012', '/images/petani/lakik.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (99, 'Daun Bawang', 8000, 34, '/images/produk/daun_bawang.jpg', 'Daun bawang segar dengan aroma harum dan batang hijau panjang. Cocok sebagai bumbu masakan, taburan sup, bakso, mie, dan berbagai hidangan Nusantara.', '250 gr', 'Aroma lebih kuat, dipanen segar setiap hari, tanpa bahan pengawet.', 'Daun bawang Desa Cibodas tumbuh subur berkat tanah vulkanik yang kaya unsur hara dan curah hujan yang tinggi sepanjang tahun. Perbedaan suhu siang dan malam membantu pembentukan minyak atsiri alami sehingga menghasilkan aroma yang lebih harum dibandingkan daun bawang dari dataran rendah. Pak Rudi bersama keluarganya telah membudidayakan tanaman ini selama lebih dari satu dekade dan tetap mempertahankan sistem panen manual agar kualitas batang tetap terjaga.', 1, 58, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (59, 'Ibu Lilis Suryani', 'Ibu Lilis Suryani', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459009', '2015', '/images/petani/pr.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (100, 'Seledri', 7000, 79, '/images/produk/seledri.jpg', 'Seledri segar dengan aroma khas dan daun hijau cerah. Cocok sebagai pelengkap sup, bakso, soto, salad, maupun jus sehat.', '200 gr', 'Kaya antioksidan, dipanen harian, daun lebih segar dan harum.', 'Seledri ini dibudidayakan di lahan pertanian yang berada di kaki perbukitan Desa Cibodas. Suhu sejuk serta sinar matahari yang cukup membuat daun tumbuh lebih hijau dengan aroma yang lebih kuat. Ibu Lilis memulai usahanya dari kebun kecil di belakang rumah, kemudian berkembang menjadi pemasok seledri bagi pasar tradisional dan berbagai restoran di kawasan Lembang. Hingga kini, setiap ikat seledri masih dipanen dan dipilih secara manual untuk memastikan kualitas terbaik sampai ke tangan pelanggan.', 5, 59, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (60, 'Pak Eman Supriatna – Cibodas Bee Farm', 'Pak Eman Supriatna – Cibodas Bee Farm', 'Jl. Maribaya RT 03/RW 03, Desa Cibodas', '6281234561409', '2014', '/images/petani/lakikk.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (101, 'Madu Kaliandra Murni', 75000, 87, '/images/produk/cookies_madu.jpg', 'Madu murni yang dihasilkan dari nektar bunga kaliandra dengan rasa manis ringan dan aroma floral yang khas.', '250 ml', '100% madu murni tanpa campuran, kaya antioksidan, dipanen secara alami.', 'Di lereng Desa Cibodas yang berada pada ketinggian sekitar 1.300 mdpl, hamparan bunga kaliandra tumbuh subur berkat udara sejuk dan tanah vulkanik yang kaya mineral. Lebah mengumpulkan nektar dari ribuan bunga setiap hari, menghasilkan madu berwarna kuning keemasan dengan aroma bunga yang lembut. Pak Eman telah membudidayakan lebah secara ramah lingkungan selama lebih dari satu dekade tanpa menggunakan bahan kimia, sehingga setiap tetes madu tetap murni dan alami.', 3, 60, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (102, 'Madu Kaliandra Murni Premium', 145000, 50, '/images/produk/cookies_madu.jpg', 'Madu kaliandra premium dengan kadar air rendah dan kualitas terbaik hasil seleksi panen.', '500 ml', 'Grade premium, rasa lebih pekat, aroma lebih kuat, cocok sebagai oleh-oleh khas Lembang.', 'Hanya madu dengan kadar air rendah dan tingkat kematangan terbaik yang dipilih sebagai varian Premium. Setiap panen hanya sebagian kecil yang memenuhi standar ini sehingga kualitas rasa, aroma, dan kekentalannya lebih istimewa. Produk ini menjadi salah satu madu favorit wisatawan yang berkunjung ke kawasan Lembang.', 3, 60, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (61, 'Ibu Nia Kartika – Lembang Honey', 'Ibu Nia Kartika – Lembang Honey', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459010', '2016', '/images/petani/prmpuan.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (103, 'Madu Multiflora', 70000, 96, '/images/produk/madu_multiflora.jpg', 'Madu alami yang dihasilkan dari berbagai jenis bunga liar di kawasan pegunungan Lembang.', '250 ml', 'Rasa lebih kompleks, kaya vitamin dan mineral alami, tanpa tambahan gula.', 'Lebah tidak hanya mengunjungi satu jenis bunga. Mereka terbang bebas melewati kebun stroberi, tanaman hortikultura, bunga liar, hingga pepohonan hutan kecil di sekitar Desa Cibodas. Perpaduan nektar dari berbagai bunga inilah yang menghasilkan madu multiflora dengan rasa unik yang berbeda di setiap musim panen.', 3, 61, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (104, 'Madu Multiflora Premium', 135000, 118, '/images/produk/madu_multiflora.jpg', 'Madu multiflora pilihan dengan kandungan nektar lebih kaya dan kualitas premium.', '500 ml', 'Dipanen saat musim bunga terbaik, tekstur lebih kental, aroma alami lebih kuat.', 'Pada musim bunga bermekaran, lebah menghasilkan madu dengan aroma dan cita rasa yang lebih kaya. Varian Premium berasal dari panen terbaik pada musim tersebut dan hanya dikemas dalam jumlah terbatas untuk menjaga kualitasnya.', 3, 61, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (62, 'UMKM HoneyFresh Cibodas', 'UMKM HoneyFresh Cibodas', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459011', '2019', '/images/petani/lakilaki.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (105, 'Honey Lemon', 48000, 105, '/images/produk/honey_lemon.jpg', 'Minuman kesehatan berbahan madu murni dan sari lemon segar yang siap dikonsumsi.', '350 ml', 'Menyegarkan, kaya vitamin C, membantu menjaga daya tahan tubuh.', 'Berawal dari kebiasaan masyarakat Desa Cibodas mengonsumsi madu hangat saat udara dingin, UMKM HoneyFresh mengembangkan minuman Honey Lemon sebagai minuman praktis yang tetap mempertahankan manfaat madu alami. Lemon segar dipilih dari kebun lokal dan dipadukan dengan madu kaliandra murni sehingga menghasilkan rasa manis, segar, dan sedikit asam yang menyenangkan.', 3, 62, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (106, 'Honey Ginger', 52000, 41, '/images/produk/honey_ginger.jpg', 'Minuman herbal berbahan madu murni dan ekstrak jahe pilihan khas dataran tinggi.', '350 ml', 'Menghangatkan tubuh, cocok diminum saat cuaca dingin, tanpa bahan pengawet.', 'Udara sejuk Desa Cibodas sering kali membuat masyarakat menikmati minuman hangat di pagi atau malam hari. Dari kebiasaan inilah lahir Honey Ginger, perpaduan madu kaliandra dengan jahe segar yang ditanam di lahan pegunungan. Minuman ini menjadi favorit wisatawan karena memberikan sensasi hangat alami sekaligus memperkenalkan cita rasa khas hasil bumi Lembang.', 3, 62, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (63, 'Pak Hendra Kurniawan', 'Pak Hendra Kurniawan', 'Jl. Cibodas RT 01/RW 07, Desa Cibodas', '6281234561410', '2011', '/images/petani/lakiiii.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (107, 'Biji kopi Arabika premium yang telah melalui proses sangrai (medium roast) sehingga menghasilkan aroma floral dan cita rasa seimbang dengan sedikit sentuhan karamel. Cocok untuk metode seduh V60, French Press, maupun Espresso.', 75000, 66, '/images/produk/biji_kakao_fermentasi.jpeg', '', '250 gr', '✔ 100% Arabika Lembang✔ Medium Roast✔ Aroma floral dan fruity✔ Dipanggang dalam batch kecil agar kualitas tetap terjaga', 'Kopi ini berasal dari kebun kopi di lereng utara Lembang pada ketinggian sekitar 1.400 mdpl. Udara yang sejuk (16–22°C), tanah vulkanik yang kaya mineral, dan kabut pagi yang rutin menyelimuti perkebunan membuat buah kopi matang lebih lambat sehingga menghasilkan rasa yang lebih kompleks dan aroma yang khas. Pak Hendra telah membudidayakan kopi Arabika bersama keluarganya selama lebih dari satu dekade dengan menerapkan panen selektif, yaitu hanya memetik buah berwarna merah sempurna agar kualitas setiap cangkir kopi tetap terjaga.', 2, 63, NOW());
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (108, 'Biji kopi Arabika Grade Specialty dengan kualitas terbaik hasil seleksi manual. Memiliki body yang lebih penuh, tingkat keasaman seimbang, serta aftertaste yang manis.', 145000, 77, '/images/produk/biji_kakao_fermentasi.jpeg', '', '500 gr', '✔ Specialty Grade✔ Dipilih dari cherry terbaik✔ Cocok untuk café dan coffee shop', 'Tidak semua buah kopi dapat menjadi kopi premium. Dari ribuan buah yang dipanen, hanya biji dengan ukuran seragam, tingkat kematangan sempurna, dan bebas cacat yang dipilih menjadi Arabika Premium. Setelah dipetik, kopi diproses secara hati-hati dan disangrai dalam jumlah kecil untuk mempertahankan karakter asli kopi pegunungan Lembang.', 2, 63, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (64, 'Kelompok Tani Kopi Cibodas', 'Kelompok Tani Kopi Cibodas', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459012', '2014', '/images/petani/perempuan dan lakik.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (109, 'Biji kopi Arabika mentah (green bean) yang telah melalui proses pencucian dan pengeringan alami. Cocok untuk roastery maupun pecinta kopi yang ingin melakukan proses roasting sendiri.', 90000, 64, '/images/produk/biji_kakao_fermentasi.jpeg', '', '500 gr', '✔ Kadar air terkontrol✔ Diproses secara natural✔ Siap untuk roasting', 'Sebelum menjadi secangkir kopi nikmat, setiap biji kopi melalui proses panjang mulai dari pemetikan buah merah, pencucian, fermentasi alami, hingga pengeringan di bawah sinar matahari pegunungan. Green Bean ini mempertahankan karakter asli kopi Lembang sehingga para roaster dapat mengembangkan profil rasa sesuai preferensi mereka.', 2, 64, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (65, 'Cibodas Coffee House', 'Cibodas Coffee House', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459013', '2019', '/images/petani/laki-laki.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (110, 'Kopi Arabika dalam kemasan drip bag praktis yang dapat langsung diseduh tanpa alat khusus. Cocok untuk dinikmati saat bekerja, bepergian, maupun di rumah.', 68000, 72, '/images/produk/brownies_kopi.jpg', '', '100 gr (10 x 10 gr)', '✔ Praktis diseduh✔ Aroma tetap terjaga✔ Tanpa gula dan bahan tambahan', 'Berawal dari banyaknya wisatawan yang ingin menikmati kopi Lembang di mana saja, UMKM Cibodas Coffee House menghadirkan kopi dalam bentuk drip bag. Meskipun praktis, setiap sachet tetap menggunakan kopi Arabika pilihan yang baru digiling sebelum dikemas sehingga aroma dan cita rasanya tetap terjaga. Dengan membeli produk ini, Anda turut mendukung petani kopi lokal serta UMKM yang mengolah hasil panen menjadi produk bernilai tinggi.', 2, 65, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (66, 'Lembang Brew Co.', 'Lembang Brew Co.', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459014', '2021', '/images/petani/lelaki.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (111, 'Konsentrat kopi Arabika yang diekstraksi menggunakan metode cold brew selama 18 jam sehingga menghasilkan rasa lebih lembut, rendah keasaman, dan aroma yang kaya. Dapat disajikan dingin maupun dicampur susu.', 85000, 44, '/images/produk/cold_brew.jpg', '', '500 ml', '✔ Ekstraksi 18 jam✔ Low Acidity✔ Tanpa pengawet✔ Siap diminum', 'Cold Brew ini dibuat dari biji kopi Arabika yang ditanam di dataran tinggi Desa Cibodas. Proses ekstraksi dingin selama 18 jam menghasilkan cita rasa yang lebih halus dibandingkan kopi seduh biasa. Setiap botol dibuat dalam jumlah terbatas menggunakan air pegunungan yang jernih agar karakter kopi tetap autentik. Produk ini menjadi bukti bagaimana hasil panen kopi lokal dapat diolah menjadi minuman modern tanpa menghilangkan identitas asalnya.', 2, 66, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (67, 'Pak Ujang Suryana', 'Pak Ujang Suryana', 'Jl. Maribaya RT 02/RW 01, Desa Cibodas', '6281234561411', '2012', '/images/petani/lelakii.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (112, 'Keranjang Bambu', 75000, 101, '/images/produk/keranjang_bambu.jpg', 'Keranjang anyaman bambu buatan tangan yang cocok digunakan sebagai wadah buah, hampers, atau dekorasi rumah.', '±800 gr', 'Dibuat 100% secara handmade menggunakan bambu pilihan, kuat, ringan, dan ramah lingkungan.', 'Di lereng Desa Cibodas, bambu tumbuh subur berkat udara pegunungan yang sejuk dan curah hujan yang tinggi. Pak Ujang memanfaatkan bambu yang telah berumur lebih dari tiga tahun agar seratnya lebih kuat dan tahan lama. Setiap keranjang dianyam secara manual selama 6–8 jam menggunakan teknik tradisional yang diwariskan dari orang tuanya. Dengan membeli produk ini, Anda turut membantu melestarikan kerajinan anyaman bambu khas masyarakat Lembang yang mulai jarang ditekuni generasi muda.', 4, 67, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (68, 'Ibu Sari Nurjanah', 'Ibu Sari Nurjanah', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459015', '2015', '/images/petani/perempuan.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (113, 'Besek', 28000, 48, '/images/produk/besek.jpg', 'Besek bambu tradisional yang biasa digunakan sebagai wadah makanan, hantaran, maupun kemasan produk UMKM.', '±350 gr', 'Ramah lingkungan, dapat digunakan kembali, dan menjadi pengganti kemasan plastik.', 'Besek ini dibuat dari bilah bambu yang dipotong tipis lalu dijemur secara alami sebelum dianyam satu per satu. Proses tersebut membuat anyaman lebih lentur dan tidak mudah patah. Bagi masyarakat Desa Cibodas, besek bukan sekadar wadah, tetapi simbol kebersamaan yang sering digunakan saat acara adat maupun pembagian hasil panen kepada tetangga.', 4, 68, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (69, 'Pak Yayan Kurnia', 'Pak Yayan Kurnia', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459016', '2018', '/images/petani/laki.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (114, 'Pot Tanaman', 95000, 110, '/images/produk/pot_tanaman.jpg', 'Pot tanaman berbahan kayu pinus lokal yang dirancang dengan desain minimalis untuk tanaman hias maupun tanaman herbal.', '±1,2 kg', 'Menggunakan kayu pinus berkualitas, finishing natural, tahan lama, dan cocok untuk dekorasi rumah.', 'Kayu pinus yang digunakan berasal dari kawasan hutan produksi di sekitar Lembang dan dipilih dari pohon yang telah memenuhi usia tebang sesuai prinsip pengelolaan hutan berkelanjutan. Setiap pot dipotong, dirakit, dan diamplas secara manual sehingga memiliki karakter serat kayu yang unik. Banyak wisatawan menjadikan produk ini sebagai oleh-oleh khas karena menghadirkan nuansa alami pegunungan Cibodas ke dalam rumah mereka.', 4, 69, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (70, 'Pak Eko Firmansyah', 'Pak Eko Firmansyah', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459017', '2016', '/images/petani/laki2.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (115, 'Rak Mini', 165000, 69, '/images/produk/rak_mini.jpg', 'Rak serbaguna berbahan kayu pinus yang dapat digunakan untuk menyimpan tanaman kecil, bumbu dapur, buku, atau dekorasi ruangan.', '±2 kg', 'Desain minimalis, kokoh, handmade, dan menggunakan kayu lokal berkualitas.', 'Awalnya Pak Eko merupakan seorang petani sayuran. Ketika musim panen selesai, ia memanfaatkan waktu luangnya untuk membuat rak kayu sederhana dari sisa kayu pinus yang tidak terpakai. Seiring meningkatnya minat masyarakat terhadap dekorasi bergaya natural, usaha kecil tersebut berkembang menjadi salah satu UMKM kerajinan unggulan Desa Cibodas. Setiap rak dibuat secara manual selama 1–2 hari dengan tetap mempertahankan tekstur alami kayu sehingga setiap produk memiliki corak yang berbeda dan tidak ada yang benar-benar sama.', 1, 70, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (71, 'UMKM Cibodas Green Snack (Ibu Rina Handayani)', 'UMKM Cibodas Green Snack (Ibu Rina Handayani)', 'Jl. Maribaya RT 03/RW 01, Desa Cibodas', '6281234561404', '2019', '/images/petani/perempuan (2).jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (116, 'Keripik Brokoli Original', 22000, 56, '/images/produk/keripik_brokoli.jpg', 'Keripik sehat berbahan brokoli segar pilihan dengan cita rasa gurih alami.', '150 gr', 'Dibuat dari brokoli Grade A, rendah minyak, tanpa pengawet, kaya serat dan vitamin.', 'Brokoli yang dipanen dari dataran tinggi Desa Cibodas tidak semuanya memiliki ukuran yang sesuai standar supermarket. Agar hasil panen tetap bernilai dan tidak terbuang sia-sia, para ibu rumah tangga mengolah brokoli pilihan menjadi keripik renyah. Kini camilan sehat ini menjadi salah satu oleh-oleh khas Lembang sekaligus membantu mengurangi limbah pangan dan meningkatkan pendapatan petani lokal.', 5, 71, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (72, 'UMKM Lestari Cibodas (Ibu Yayah Suryani)', 'UMKM Lestari Cibodas (Ibu Yayah Suryani)', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459018', '2018', '/images/petani/pr.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (117, 'Keripik Bayam Original', 18000, 39, '/images/produk/keripik_bayam.jpg', 'Keripik bayam dengan tekstur renyah dan rasa gurih alami.', '120 gr', 'Menggunakan bayam segar panen pagi, tanpa pewarna buatan, kaya zat besi dan serat.', 'Bayam yang tumbuh di udara sejuk Desa Cibodas memiliki daun yang lebih lebar dan segar berkat tanah vulkanik yang kaya mineral. Daun-daun pilihan dipetik saat matahari belum terlalu tinggi agar kesegarannya tetap terjaga sebelum diolah menjadi keripik yang renyah dan bergizi.', 5, 72, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (73, 'UMKM Cibodas Crispy (Pak Irfan Hidayat)', 'UMKM Cibodas Crispy (Pak Irfan Hidayat)', 'Jl. Maribaya RT 01/RW 04, Desa Cibodas', '6281234561406', '2017', '/images/petani/lakik.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (118, 'Keripik Kentang Original', 20000, 42, '/images/produk/keripik_kentang.jpg', 'Keripik kentang tipis dengan rasa gurih alami khas kentang dataran tinggi.', '180 gr', 'Menggunakan kentang Granola pilihan, tanpa bahan pengawet, renyah lebih lama.', 'Kentang yang tumbuh di dataran tinggi Lembang memiliki kadar air lebih rendah sehingga menghasilkan tekstur yang padat dan renyah saat digoreng. Setiap kentang diiris tipis menggunakan alat khusus, lalu dimasak dengan suhu yang terkontrol agar menghasilkan kerenyahan sempurna tanpa menghilangkan cita rasa alami kentang pegunungan.', 6, 73, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (74, 'UMKM Berry Lembang (Ibu Lina Marlina)', 'UMKM Berry Lembang (Ibu Lina Marlina)', 'Desa Cibodas, Kec. Lembang, Kab. Kabupaten Bandung Barat', '628123459019', '2016', '/images/petani/prmpuan.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (119, 'Dodol Stroberi', 32000, 78, '/images/produk/dodol_stroberi.jpg', 'Dodol tradisional dengan rasa manis alami dari stroberi segar Lembang.', '250 gr', 'Mengandung buah stroberi asli, tekstur lembut, tanpa pewarna sintetis.', 'Saat musim panen raya, sebagian stroberi matang tidak dapat dijual sebagai buah segar karena umur simpannya yang pendek. Agar hasil panen tetap bernilai ekonomi, masyarakat Desa Cibodas mengolahnya menjadi dodol stroberi dengan resep turun-temurun. Perpaduan buah segar dan proses memasak perlahan menghasilkan rasa manis alami yang menjadi favorit wisatawan.', 6, 74, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (75, 'UMKM Berry Valley (Ibu Siti Nurhayati)', 'UMKM Berry Valley (Ibu Siti Nurhayati)', 'Jl. Maribaya RT 04/RW 05, Desa Cibodas', '6281234561408', '2020', '/images/petani/perempuan.jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (120, 'Permen Stroberi', 16000, 84, '/images/produk/permen_stroberi.jpg', 'Permen buah dengan ekstrak stroberi asli yang menyegarkan.', '100 gr', 'Menggunakan sari buah stroberi lokal, rasa buah lebih dominan, praktis dibawa bepergian.', 'Terinspirasi dari melimpahnya hasil panen stroberi di Desa Cibodas, para pelaku UMKM menciptakan permen stroberi sebagai camilan praktis yang dapat dinikmati kapan saja. Setiap butir permen dibuat dari sari buah stroberi asli sehingga menghadirkan aroma khas dataran tinggi Lembang dalam setiap gigitan.', 6, 75, NOW());
INSERT INTO umkm (id, nama, pemilik, alamat, no_hp, sejak, foto, desa_id) OVERRIDING SYSTEM VALUE VALUES (76, 'UMKM Sehat Lestari Cibodas (Ibu Dewi Kartika)', 'UMKM Sehat Lestari Cibodas (Ibu Dewi Kartika)', 'Jl. Maribaya RT 05/RW 03, Desa Cibodas', '6281234561412', '2021', '/images/petani/perempuan (2).jpeg', 4);
INSERT INTO produk (id, nama, harga, stok, gambar, deskripsi, satuan, keunggulan, cerita, kategori_id, umkm_id, created_at) OVERRIDING SYSTEM VALUE VALUES (121, 'Stik Sayuran', 24000, 92, '/images/produk/bayam_hijau.jpg', 'Camilan sehat berbahan campuran bayam, wortel, brokoli, dan pakcoy.', '180 gr', 'Menggunakan sayuran segar lokal, tanpa pengawet, kaya serat dan vitamin.', 'Stik sayuran lahir dari semangat masyarakat Desa Cibodas untuk mengolah hasil panen hortikultura menjadi camilan yang disukai semua kalangan, terutama anak-anak. Campuran brokoli, bayam, wortel, dan pakcoy dipilih langsung dari kebun petani lokal, kemudian diolah menjadi stik renyah tanpa menghilangkan cita rasa alami sayuran. Setiap pembelian produk ini turut mendukung keberlanjutan UMKM desa dan mengurangi potensi terbuangnya hasil panen segar.', 5, 76, NOW());
INSERT INTO desa (id, nama_desa, kecamatan, kabupaten, latitude, longitude, deskripsi) OVERRIDING SYSTEM VALUE VALUES (5, 'Desa Wisata Nglanggeran', 'Patuk', 'Kabupaten Gunungkidul', -7.8522, 110.5123, 'Desa Wisata Nglanggeran di Gunungkidul, Yogyakarta, terkenal dengan Gunung Api Purba dan budidaya kakao. Masyarakat mengolah kakao menjadi cokelat premium, snack, dan minuman khas desa.');
